public sealed class HungerConfigV3
{
    public float DefaultInitialHunger{get;init;}=.20f;public float HungerIncreasePerSecond{get;init;}=.00035f;public float HungryThreshold{get;init;}=.35f;public float VeryHungryThreshold{get;init;}=.65f;public float CriticalEatPriorityThreshold{get;init;}=.85f;public float StarvingThreshold{get;init;}=.90f;public float AutoEatThreshold{get;init;}=.65f;public float ManualEatMinimumHunger{get;init;}=.20f;public int HungerCalorieCapacity{get;init;}=1000;public float MealTargetHunger{get;init;}=.20f;
    public bool IsValid=>float.IsFinite(DefaultInitialHunger)&&DefaultInitialHunger is >=0 and <=1&&HungerIncreasePerSecond>=0&&HungryThreshold>=0&&HungryThreshold<VeryHungryThreshold&&VeryHungryThreshold<CriticalEatPriorityThreshold&&CriticalEatPriorityThreshold<=StarvingThreshold&&StarvingThreshold<=1&&AutoEatThreshold==VeryHungryThreshold&&ManualEatMinimumHunger>=0&&HungerCalorieCapacity>0&&MealTargetHunger is >=0 and <1;
}
public sealed class MercenaryHungerStateV3
{
    internal MercenaryHungerStateV3(string id,float initial){MercenaryId=id;HungerNormalized=Math.Clamp(initial,0,1);CreatedUtc=DateTime.UtcNow;}public string MercenaryId{get;}public float HungerNormalized{get;private set;}public long Revision{get;private set;}public DateTime CreatedUtc{get;}public bool IsHungry=>HungerNormalized>=.35f;public bool IsVeryHungry=>HungerNormalized>=.65f;public bool IsStarving=>HungerNormalized>=.90f;
    public bool TrySetHunger(float value,out string reason){if(!float.IsFinite(value)){reason="InvalidHungerValue";return false;}float next=Math.Clamp(value,0,1);if(Math.Abs(next-HungerNormalized)<.000001f){reason=string.Empty;return true;}HungerNormalized=next;Revision++;reason=string.Empty;return true;}public bool TryAddHunger(float value,out string reason)=>float.IsFinite(value)&&value>=0?TrySetHunger(HungerNormalized+value,out reason):Fail(out reason);public bool TryReduceHunger(float value,out string reason)=>float.IsFinite(value)&&value>=0?TrySetHunger(HungerNormalized-value,out reason):Fail(out reason);private static bool Fail(out string reason){reason="InvalidHungerValue";return false;}
}
public sealed class MercenaryHungerRegistryV3
{
    private readonly Dictionary<string,MercenaryHungerStateV3> _states=new(StringComparer.Ordinal);private readonly HungerConfigV3 _config;public MercenaryHungerRegistryV3(HungerConfigV3 config){_config=config;}public int Count=>_states.Count;public long Revision{get;private set;}public MercenaryHungerStateV3 EnsureForMercenary(string id){if(!_states.TryGetValue(id,out var state)){state=new(id,_config.DefaultInitialHunger);_states.Add(id,state);Revision++;}return state;}public bool TryGet(string id,out MercenaryHungerStateV3? state)=>_states.TryGetValue(id,out state);public float GetHunger(string id)=>_states.TryGetValue(id,out var state)?state.HungerNormalized:_config.DefaultInitialHunger;public bool TryRemove(string id){if(!_states.Remove(id))return false;Revision++;return true;}public void Clear(){if(_states.Count==0)return;_states.Clear();Revision++;}
}
public static class HungerPolicyV3
{
    public static float WorkMultiplier(float hunger)=>hunger>=.90f?.60f:hunger>=.65f?.80f:hunger>=.35f?.95f:1f;public static string Stage(float hunger)=>hunger>=.90f?"굶주림":hunger>=.65f?"매우 배고픔":hunger>=.35f?"배고픔":"든든함";
}
public enum EatingCommandSourceV3{DirectOrder,NeedAutoEat}
public enum NeedActionKindV3{Eat,Rest}
public static class NeedActionPriorityV3
{
    public static IReadOnlyList<NeedActionKindV3> GetCandidates(float hunger,float fatigue,HungerConfigV3 hungerConfig,MercenaryFatigueSettingsV3 fatigueConfig){List<NeedActionKindV3> result=new(4);if(hunger>=hungerConfig.CriticalEatPriorityThreshold)result.Add(NeedActionKindV3.Eat);if(fatigue>=fatigueConfig.ExhaustedThreshold)result.Add(NeedActionKindV3.Rest);if(hunger>=hungerConfig.AutoEatThreshold&&hunger<hungerConfig.CriticalEatPriorityThreshold)result.Add(NeedActionKindV3.Eat);if(fatigue>=fatigueConfig.AutoRestThreshold&&fatigue<fatigueConfig.ExhaustedThreshold)result.Add(NeedActionKindV3.Rest);return result.AsReadOnly();}
}
