public static class InitialRationPlacementServiceV3
{
    private static readonly Vector2I[] Offsets={new(2,0),new(-2,0),new(0,2),new(0,-2),new(3,1),new(-3,1),new(1,3),new(1,-3),new(4,0),new(-4,0),new(0,4),new(0,-4),new(5,0),new(-5,0),new(0,5),new(0,-5)};
    public static bool TryPlace(ResourceSessionV3 resources,CompanyDeploymentStateV3 deployment,Rect2I bounds,Func<Vector2I,bool> walkable,out GroundResourceStackV3? stack,out string reason){stack=null;if(resources.InitialRationPlacementInitialized){if(resources.GroundStacks.TryGet(resources.InitialRationStackId,out stack)){reason=string.Empty;return true;}reason="InitialRationStateMissing";return false;}HashSet<Vector2I> occupied=new(deployment.FormationCells.Select(x=>x.Value)){deployment.DeploymentAnchorCell.Value};foreach(Vector2I offset in Offsets){Vector2I cell=deployment.DeploymentAnchorCell.Value+offset;if(!bounds.HasPoint(cell)||occupied.Contains(cell)||!walkable(cell))continue;if(resources.GroundStacks.GetStacksAtCell(new(cell)).Count>0)continue;if(!resources.GroundStacks.TryAddStack(ResourceTypeV3.Ration,18,new(cell),out stack,out _,out reason)||stack==null)return false;resources.InitialRationPlacementInitialized=true;resources.InitialRationStackId=stack.ResourceStackId;return true;}reason="NoRationPlacementCandidate";return false;}
}

public static class HungerEatingSelfCheckV3
{
    public static bool TryValidate(out string reason){HungerConfigV3 config=new();if(!config.IsValid){reason="Invalid hunger config.";return false;}MercenaryHungerRegistryV3 registry=new(config);var state=registry.EnsureForMercenary("merc_test");if(Math.Abs(state.HungerNormalized-.2f)>.0001f){reason="Initial hunger mismatch.";return false;}long revision=state.Revision;if(!state.TrySetHunger(.2f,out _)||state.Revision!=revision||state.TrySetHunger(float.NaN,out _)||state.TrySetHunger(float.PositiveInfinity,out _)){reason="Hunger value validation failed.";return false;}state.TryAddHunger(.8f,out _);if(state.HungerNormalized!=1f){reason="Hunger upper clamp failed.";return false;}state.TryReduceHunger(2f,out _);if(state.HungerNormalized!=0f){reason="Hunger lower clamp failed.";return false;}if(HungerPolicyV3.WorkMultiplier(.1f)!=1f||HungerPolicyV3.WorkMultiplier(.4f)!=.95f||HungerPolicyV3.WorkMultiplier(.7f)!=.8f||HungerPolicyV3.WorkMultiplier(.95f)!=.6f){reason="Hunger multiplier bands failed.";return false;}ResourceSessionV3 resources=new();resources.GroundStacks.TryAddStack(ResourceTypeV3.Ration,10,new(new Godot.Vector2I(1,1)),out var stack,out _,out _);if(stack==null||!resources.AmountReservations.TryReserve(stack.ResourceStackId,"merc_a","eat_a",ResourceTypeV3.Ration,1,ResourceAmountReservationPurposeV3.FoodConsumption,out var eating,out reason)||resources.AmountReservations.GetAvailableAmount(stack.ResourceStackId)!=9||!resources.AmountReservations.TryReserve(stack.ResourceStackId,"merc_b","haul_b",ResourceTypeV3.Ration,9,ResourceAmountReservationPurposeV3.HaulingPickup,out _,out reason)||resources.AmountReservations.GetAvailableAmount(stack.ResourceStackId)!=0){reason="Shared amount reservation failed.";return false;}resources.AmountReservations.ReleaseByWorkRequest("haul_b");if(eating==null||!resources.AmountReservations.TryConsume(eating.ReservationId,"merc_a","eat_a",out _,out _,out reason)||resources.GroundStacks.GetTotalAmount(ResourceTypeV3.Ration)!=9){return false;}if(!resources.ConsumptionLedger.TryRecord(ResourceTypeV3.Ration,1,"Eating","merc_a","eat_a")||resources.ConsumptionLedger.TryRecord(ResourceTypeV3.Ration,1,"Eating","merc_a","eat_a")||resources.ConsumptionLedger.GetConsumedAmount(ResourceTypeV3.Ration)!=1){reason="Consumption ledger failed.";return false;}foreach(WorldMapSizePresetV2 preset in Enum.GetValues<WorldMapSizePresetV2>()){Rect2I bounds=WorldMapSizeDefinitionV2.FromPreset(preset).CellBounds;Vector2I center=bounds.GetCenter();CompanyDeploymentStateV3 deployment=new("company",1,0,new(center),new(center),new[]{new GlobalCellCoord(center+Vector2I.Left),new GlobalCellCoord(center),new GlobalCellCoord(center+Vector2I.Right)},DateTime.UtcNow,1,0,0,0);ResourceSessionV3 presetResources=new();if(!InitialRationPlacementServiceV3.TryPlace(presetResources,deployment,bounds,_=>true,out var ration,out reason)||ration?.Amount!=18){reason=$"{preset} ration placement failed: {reason}";return false;}string rationId=ration.ResourceStackId;if(!InitialRationPlacementServiceV3.TryPlace(presetResources,deployment,bounds,_=>true,out ration,out reason)||ration?.ResourceStackId!=rationId||ration.Amount!=18){reason=$"{preset} ration placement idempotency failed.";return false;}}reason=string.Empty;return true;}
}
